// Fallback in-memory and local file store for shared itineraries in case Firebase is absent
const memorySharedStore = new Map<string, any>();
const LOCAL_SHARE_FILE = path.join(process.cwd(), "shared_itineraries_fallback.json");

function saveFallbackShare(id: string, itinerary: any) {
  memorySharedStore.set(id, itinerary);
  try {
    let currentStore: Record<string, any> = {};
    if (fs.existsSync(LOCAL_SHARE_FILE)) {
      currentStore = JSON.parse(fs.readFileSync(LOCAL_SHARE_FILE, "utf-8"));
    }
    currentStore[id] = itinerary;
    fs.writeFileSync(LOCAL_SHARE_FILE, JSON.stringify(currentStore, null, 2), "utf-8");
  } catch (err) {
    console.warn("[Fallback Share] Failed to persist fallback travel share file:", err);
  }
}

function getFallbackShare(id: string): any | null {
  if (memorySharedStore.has(id)) {
    return memorySharedStore.get(id);
  }
  try {
    if (fs.existsSync(LOCAL_SHARE_FILE)) {
      const currentStore = JSON.parse(fs.readFileSync(LOCAL_SHARE_FILE, "utf-8"));
      if (currentStore[id]) {
        memorySharedStore.set(id, currentStore[id]);
        return currentStore[id];
      }
    }
  } catch (err) {
    console.warn("[Fallback Share] Failed to read fallback travel share file:", err);
  }
  return null;
}

try {
  const configPath = path.join(process.cwd(), "firebase-applet-config.json");
  if (fs.existsSync(configPath)) {
    const firebaseConfig = JSON.parse(fs.readFileSync(configPath, "utf-8"));
    const firebaseApp = initializeApp(firebaseConfig);
    db = getFirestore(firebaseApp, firebaseConfig.firestoreDatabaseId);
    firebaseEnabled = true;
    console.log("[Firebase] Successfully initialized persistently using config file.");
  } else {
    console.warn("[Firebase] Config file missing. Sharing will fall back to local JSON storage.");
  }
} catch (error) {
  console.error("[Firebase] Initialization failed:", error);
}

// Mandated operation types and error format config for robust debugging
enum OperationType {
  CREATE = 'create',
  UPDATE = 'update',
  DELETE = 'delete',
  LIST = 'list',
  GET = 'get',
  WRITE = 'write',
}

interface FirestoreErrorInfo {
  error: string;
  operationType: OperationType;
  path: string | null;
  authInfo: {
    userId?: string | null;
    email?: string | null;
    emailVerified?: boolean | null;
    isAnonymous?: boolean | null;
    tenantId?: string | null;
    providerInfo?: any[];
  };
}

function handleFirestoreError(error: unknown, operationType: OperationType, path: string | null): never {
  const errInfo: FirestoreErrorInfo = {
    error: error instanceof Error ? error.message : String(error),
    authInfo: {
      userId: null,
      email: null,
      emailVerified: null,
      isAnonymous: null,
      tenantId: null,
      providerInfo: []
    },
    operationType,
    path
  };
  console.error('[Firebase Database Audit] Failure Detected: ', JSON.stringify(errInfo));
  throw new Error(JSON.stringify(errInfo));
}

