/**
 * Helper to call Gemini API with robust retry and automatic model fallback.
 * Checks for transient errors (like 503 high demand or 429 rate limit)
 * and retries with exponential backoff.
 * If gemini-3.5-flash remains unavailable, it automatically falls back to gemini-3.1-flash-lite.
 */
async function generateContentWithRetryAndFallback(params: {
  contents: any;
  config: any;
  systemInstruction?: string;
}) {
  const primaryModel = "gemini-3.5-flash";
  const backupModel = "gemini-3.1-flash-lite";
  
  const callWithBackoff = async (modelName: string, maxRetries = 3, initialDelayMs = 1000) => {
    let attempt = 0;
    while (true) {
      try {
        console.log(`[Gemini API] Querying model ${modelName} (Attempt ${attempt + 1}/${maxRetries})...`);
        const response = await ai.models.generateContent({
          model: modelName,
          contents: params.contents,
          config: {
            ...params.config,
            ...(params.systemInstruction ? { systemInstruction: params.systemInstruction } : {}),
          }
        });
        return response;
      } catch (err: any) {
        attempt++;
        const errMsg = err.message || String(err);
        const errStatus = err.status || (err.error && err.error.code) || 0;
        
        // Check for common transient codes: 503 (Unavailable), 429 (Rate limit / Resource Exhausted), 500 (Internal Server Error)
        const isTransient = 
          errMsg.includes("503") || 
          errMsg.includes("status: 503") ||
          errMsg.includes("UNAVAILABLE") || 
          errMsg.includes("429") || 
          errMsg.includes("RESOURCE_EXHAUSTED") ||
          errMsg.includes("500") ||
          errStatus === 503 ||
          errStatus === 429 ||
          errStatus === 500;
          
        if (isTransient && attempt < maxRetries) {
          const delay = initialDelayMs * Math.pow(2, attempt - 1);
          console.warn(`[Gemini API Retry] Model ${modelName} failed with transient error: "${errMsg}". Retrying in ${delay}ms...`);
          await new Promise(resolve => setTimeout(resolve, delay));
          continue;
        }
        throw err;
      }
    }
  };

  try {
    // Attempt with the primary model first (max 2 attempts to minimize latency pressure)
    const response = await callWithBackoff(primaryModel, 2, 800);
    return { response, modelUsed: primaryModel };
  } catch (primaryError: any) {
    console.error(`[Gemini API Primary Error] Primary model "${primaryModel}" completely unsuccessful:`, primaryError.message || primaryError);
    
    // Check if it's transient/unavailable/demand-related so we fallback to the lighter backup model
    console.log(`[Gemini API Fallback] Triggering automatic backup fallback to model: "${backupModel}"...`);
    try {
      const response = await callWithBackoff(backupModel, 2, 800);
      return { response, modelUsed: backupModel };
    } catch (backupError: any) {
      console.error(`[Gemini API Backup Error] Fallback model "${backupModel}" also unsuccessful:`, backupError.message || backupError);
      throw primaryError; // Throw the primary error to show the root cause of the demand issue
    }
  }
}

