// --- Shared Itineraries Storage ---
// We have migrated from stateless local file-based storage to a persistent Firestore database
// to prevent link expirations and publish stalling issues when Cloud Run containers scale or restart.

async function saveSharedItineraryFirebase(id: string, itinerary: any): Promise<void> {
  const docPath = `shared_itineraries/${id}`;
  if (!db) {
    saveFallbackShare(id, itinerary);
    return;
  }
  try {
    const docRef = doc(db, 'shared_itineraries', id);
    // Ensure the payload structure is clean and append creation metadata
    const payload = {
      ...itinerary,
      createdAt: new Date().toISOString()
    };
    await setDoc(docRef, payload);
  } catch (err) {
    console.warn('[Firebase Database] Failed to write. Using local fallback...', err);
    saveFallbackShare(id, itinerary);
  }
}

async function getSharedItineraryFirebase(id: string): Promise<any | null> {
  const docPath = `shared_itineraries/${id}`;
  if (!db) {
    return getFallbackShare(id);
  }
  try {
    const docRef = doc(db, 'shared_itineraries', id);
    const docSnap = await getDoc(docRef);
    if (docSnap.exists()) {
      return docSnap.data();
    }
    return getFallbackShare(id);
  } catch (err) {
    console.warn('[Firebase Database] Failed to read. Checking local fallback...', err);
    return getFallbackShare(id);
  }
}

// 2. Share Save Endpoint
app.post("/api/itinerary/share", async (req, res) => {
  try {
    const { itinerary } = req.body;
    if (!itinerary) {
      return res.status(400).json({ error: "Missing itinerary to share" });
    }
    // Generate a unique 9-character trip sharing identification code
    const id = Math.random().toString(36).substring(2, 11);
    await saveSharedItineraryFirebase(id, itinerary);
    return res.json({ success: true, id });
  } catch (err: any) {
    console.error("Share endpoint error:", err);
    return res.status(500).json({ error: err.message || "Failed to save sharing instance" });
  }
});

// 3. Share Retrieval Endpoint
app.get("/api/itinerary/share/:id", async (req, res) => {
  try {
    const { id } = req.params;
    const itinerary = await getSharedItineraryFirebase(id);
    if (!itinerary) {
      return res.status(404).json({ error: "Itinerary not found or link has expired." });
    }
    return res.json({ success: true, itinerary });
  } catch (err: any) {
    console.error("Share Retrieval endpoint error:", err);
    return res.status(500).json({ error: err.message || "Failed to load sharing instance" });
  }
});



// Helper to determine typical dynamic sliding budget ranges for a selected location
app.get("/api/itinerary/calculate-local-budget", async (req, res) => {
  const { destination } = req.query;
  const destName = String(destination || "").trim();

  // Pick suitable benchmarks based on typical standard city profiles
  const lowerDest = destName.toLowerCase();
  let baseCost = { budget: 100, balanced: 220, luxury: 600 };

  if (lowerDest.includes("tokyo") || lowerDest.includes("japan") || lowerDest.includes("kyoto")) {
    baseCost = { budget: 90, balanced: 200, luxury: 550 };
  } else if (lowerDest.includes("amalfi") || lowerDest.includes("italy") || lowerDest.includes("rome") || lowerDest.includes("paris") || lowerDest.includes("london") || lowerDest.includes("swiss") || lowerDest.includes("switzerland")) {
    baseCost = { budget: 140, balanced: 300, luxury: 700 };
  } else if (lowerDest.includes("hawaii") || lowerDest.includes("maui") || lowerDest.includes("new york") || lowerDest.includes("nyc") || lowerDest.includes("california") || lowerDest.includes("san francisco")) {
    baseCost = { budget: 160, balanced: 320, luxury: 800 };
  } else if (lowerDest.includes("thailand") || lowerDest.includes("bali") || lowerDest.includes("indonesia") || lowerDest.includes("vietnam") || lowerDest.includes("india") || lowerDest.includes("costa rica")) {
    baseCost = { budget: 40, balanced: 90, luxury: 290 };
  } else if (lowerDest.includes("canada") || lowerDest.includes("banff") || lowerDest.includes("alaska")) {
    baseCost = { budget: 110, balanced: 240, luxury: 650 };
  } else if (lowerDest.includes("new zealand") || lowerDest.includes("queenstown") || lowerDest.includes("australia") || lowerDest.includes("sydney")) {
    baseCost = { budget: 100, balanced: 220, luxury: 580 };
  } else {
    // If not in standard pre-calculated, query Gemini dynamically if API key is present
    if (destName && process.env.GEMINI_API_KEY) {
      try {
        const { response } = await generateContentWithRetryAndFallback({
          contents: `Provide a realistic, modern travel daily cost estimate (in USD, per standard individual, excluding flights) for the destination: "${destName}".
We need three tiers:
- "budget": low cost (hostels, street food, super inexpensive)
- "balanced": standard comfort (mid-range hotels, sit-down dining, typical entrance tickets)
- "luxury": high-end luxury (4-5 star hotels, fine dining, private tours)

Respond STRICTLY with a single JSON object containing only these three fields: "budget" (integer), "balanced" (integer), "luxury" (integer).
Example format:
{ "budget": 65, "balanced": 160, "luxury": 420 }
Do not include any styling, explanation, or markdown blocks. Return only valid raw JSON.`,
          config: {}
        });

        const textResponse = response.text?.trim() || "";
        const jsonStr = textResponse.replace(/```json|```/gi, "").trim();
        const parsed = JSON.parse(jsonStr);
        if (parsed && typeof parsed.budget === 'number' && typeof parsed.balanced === 'number' && typeof parsed.luxury === 'number') {
          baseCost = {
            budget: Math.max(15, parsed.budget),
            balanced: Math.max(parsed.budget + 10, parsed.balanced),
            luxury: Math.max(parsed.balanced + 25, parsed.luxury)
          };
          console.log(`[Budget] Dynamic calculation for "${destName}" succeeded:`, baseCost);
          return res.json(baseCost);
        }
      } catch (err: any) {
        console.warn(`[Budget] Dynamic budget generation call failed for "${destName}":`, err.message || err);
      }
    }
  }

  res.json(baseCost);
});

